var __webpack_exports__ = {};
const express = __nccwpck_require__(5835);
const http = __nccwpck_require__(8611);
const { Server } = __nccwpck_require__(834);
const cors = __nccwpck_require__(1784);

const app = express();
app.use(cors());
app.use(express.static(__dirname)); // Serve static files from root

const server = http.createServer(app);
const io = new Server(server, {
    cors: {
        origin: "*",
        methods: ["GET", "POST"]
    }
});

const CARD_TYPES = [
    { type: 'NORMAL_1', count: 1, skip: false, label: 'Normal' },
    { type: 'NORMAL_2', count: 2, skip: true, label: 'Double Normal' },
    { type: 'PHONE_1', count: 1, skip: false, label: 'Phone' },
    { type: 'PHONE_2', count: 2, skip: true, label: 'Double Phone' },
    { type: 'GUN_1', count: 1, skip: false, label: 'Gun' },
    { type: 'GUN_2', count: 2, skip: true, label: 'Double Gun' },
];

const rooms = new Map();

function shuffle(array) {
    for (let i = array.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [array[i], array[j]] = [array[j], array[i]];
    }
    return array;
}

function createDeck() {
    let deck = [];
    // 100 cards total
    for (let i = 0; i < 100; i++) {
        const template = CARD_TYPES[Math.floor(Math.random() * CARD_TYPES.length)];
        deck.push({ ...template, id: i });
    }
    return shuffle(deck);
}

function getNextCount(current, direction) {
    let next = current + direction;
    let nextDirection = direction;
    if (next > 7) {
        next = 6;
        nextDirection = -1;
    } else if (next < 1) {
        next = 2;
        nextDirection = 1;
    }
    return { next, nextDirection };
}

io.on('connection', (socket) => {
    console.log('User connected:', socket.id);

    socket.on('join_room', ({ roomId, username }) => {
        socket.join(roomId);
        if (!rooms.has(roomId)) {
            rooms.set(roomId, {
                id: roomId,
                players: [],
                status: 'waiting',
                gameState: null
            });
        }
        const room = rooms.get(roomId);
        if (room.status !== 'waiting') {
            socket.emit('error', 'Game already started');
            return;
        }
        
        const player = {
            id: socket.id,
            username,
            deck: [],
            score: 0
        };
        room.players.push(player);
        io.to(roomId).emit('room_update', room);
    });

    socket.on('start_game', (roomId) => {
        const room = rooms.get(roomId);
        if (!room || room.players.length < 2) return;

        const deck = createDeck();
        const cardsPerPlayer = Math.floor(100 / room.players.length);
        
        room.players.forEach((p, idx) => {
            p.deck = deck.slice(idx * cardsPerPlayer, (idx + 1) * cardsPerPlayer);
        });

        room.status = 'playing';
        room.gameState = {
            currentTurn: 0,
            currentNumber: 1,
            direction: 1, // 1 for up, -1 for down
            lastCard: null,
            history: [],
            winner: null,
            subTurn: 0 // for double cards
        };

        io.to(roomId).emit('game_started', room);
    });

    socket.on('play_card', ({ roomId, action }) => {
        const room = rooms.get(roomId);
        if (!room || room.status !== 'playing') return;

        const state = room.gameState;
        const currentPlayer = room.players[state.currentTurn];

        if (currentPlayer.id !== socket.id) return;

        const currentCard = currentPlayer.deck[0];
        if (!currentCard) return;

        // Validate Action
        let isValid = false;
        let expectedAction = '';

        if (currentCard.type.startsWith('NORMAL')) {
            expectedAction = state.currentNumber.toString();
        } else if (currentCard.type.startsWith('PHONE')) {
            expectedAction = 'hello';
        } else if (currentCard.type.startsWith('GUN')) {
            expectedAction = 'Я╣ђЯИЄЯИхЯИбЯИџ';
        }

        if (action === expectedAction) {
            isValid = true;
        }

        if (isValid) {
            // Success
            state.lastCard = currentCard;
            currentPlayer.deck.shift();

            // Check Win
            if (currentPlayer.deck.length === 0) {
                state.winner = currentPlayer.username;
                room.status = 'finished';
                io.to(roomId).emit('game_over', room);
                return;
            }

            // Move Game State
            state.subTurn++;
            
            // Get next number for EVERYTHING (including phone and gun, as they count too)
            const { next, nextDirection } = getNextCount(state.currentNumber, state.direction);
            state.currentNumber = next;
            state.direction = nextDirection;

            // Handle multi-count cards (Double cards)
            if (state.subTurn < currentCard.count) {
                // Same player continues
                io.to(roomId).emit('update_game_state', room);
            } else {
                // Turn ends
                state.subTurn = 0;
                let nextTurn = (state.currentTurn + 1) % room.players.length;
                if (currentCard.skip) {
                    nextTurn = (nextTurn + 1) % room.players.length;
                }
                state.currentTurn = nextTurn;
                io.to(roomId).emit('update_game_state', room);
            }
        } else {
            // Penalty: Move deck to back, or maybe draw more cards? 
            // In typical speed games, you just get stuck. 
            // Let's say if wrong, you draw 2 cards from a "penalty deck" or just don't progress.
            // Simplified: Nothing happens, player must press correct button.
            socket.emit('wrong_move');
        }
    });

    socket.on('disconnect', () => {
        console.log('User disconnected');
        // Handle cleanup
    });
});

const PORT = process.env.PORT || 3001;
app.get('/', (req, res) => {
    res.sendFile(__nccwpck_require__.ab + "index.html");
});
server.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}`);
});

module.exports = __webpack_exports__;
